// @name         YMS Quick Notes & UI Improvements - OXY_OS Edition (Optimized)
// @version      3.1
// @description  Technical FUI Overhaul for YMS Dashboard. High Performance Brutalist Technocracy Style.
// @author       @R&S (Optimized)
// @match        https://trans-logistics.amazon.com/yms/shipclerk/*
// @match        https://trans-logistics-eu.amazon.com/yms/shipclerk/*
// @icon         https://api.iconify.design/skill-icons:aws-dark.svg
// @grant        GM_addStyle
// @require      https://code.jquery.com/jquery-3.7.0.min.js
// @run-at       document-end
// ==/UserScript==

/* global jQuery */

(function ($, window, document) {
    'use strict';

    // --- CONFIGURATION ---
    const THEME = {
        ACCENT: "#ff3c00", // Zaktualizowano na techniczny pomarańcz z wytycznych
        BG_DARK: "#121212", // Głębsza czerń OXY_OS
        SECONDARY: "#555555",
        DATA_WHITE: "#FFFFFF",
        SUCCESS: "#00FF41",
        INFO: "#0080FF"
    };

    const QUICK_NOTES_CONFIG = {
        page1: {
            "SYSTEM_GENERAL": [
                { text: "RESET", class: "btn-reset", value: "  " },
                { text: "SHIPL", class: "btn-std", value: "SHIP LOAD: " },
                { text: "RENTAL", class: "btn-std", value: "RENTAL VS4 " }
            ],
            "IXD_OPERATIONS": [
                { text: "FWBF1", class: "btn-alert", value: "IXD FWBF1 D&S ISA " },
                { text: "FWBK1", class: "btn-data", value: "IXD FWBK1 D&S ISA " },
                { text: "FWBK2", class: "btn-data", value: "IXD FWBK2 D&S ISA " },
                { text: "FWBK3", class: "btn-data", value: "IXD FWBK3 D&S ISA " },
                { text: "FWBK4", class: "btn-data", value: "IXD FWBK4 D&S ISA " },
                { text: "FWBS1", class: "btn-ok", value: "IXD FWBS1 D&S ISA " },
                { text: "FWBS5", class: "btn-ok", value: "IXD FWBS5 D&S ISA " },
                { text: "FWBS6", class: "btn-ok", value: "IXD FWBS6 D&S ISA " },
                { text: "FWBS7", class: "btn-ok", value: "IXD FWBS7 D&S ISA " },
                { text: "FWBS8", class: "btn-ok", value: "IXD FWBS8 D&S ISA " },
                { text: "FWS10", class: "btn-ok", value: "IXD FWS10 D&S ISA " },
                { text: "FWS12", class: "btn-ok", value: "IXD FWS12 D&S ISA " },
                { text: "FWS13", class: "btn-ok", value: "IXD FWS13 D&S ISA " },
                { text: "FWS14", class: "btn-ok", value: "IXD FWS14 D&S ISA " },
                { text: "FWS15", class: "btn-ok", value: "IXD FWS15 D&S ISA " },
                { text: "FWS16", class: "btn-ok", value: "IXD FWS16 D&S ISA " },
                { text: "AKWPS", class: "btn-alert", value: "IXD AKWPS D&S ISA " },
                { text: "AWZXP", class: "btn-alert", value: "IXD AWZXP D&S ISA " },
                { text: "ATSEU", class: "btn-alert", value: "IXD ATSEU D&S ISA " },
                { text: "FBAPL", class: "btn-alert", value: "IXD FBA PALLETS D&S VRID " },
                { text: "RETAIL", class: "btn-alert", value: "IXD RETAIL PALLETS D&S ISA " },
                { text: "FBALL", class: "btn-alert", value: "IXD FBALL D&S ISA " }
            ],
            "COURIER_LOG": [
                { text: "UPSN", class: "btn-sec", value: "IXD UPSN D&S ISA " },
                { text: "LEG25", class: "btn-sec", value: "IXD LEG25 D&S ISA " },
                { text: "DPDPL", class: "btn-sec", value: "IXD DPDPL D&S ISA " },
                { text: "ICCLL", class: "btn-data", value: "IXD ICWR5 PARCEL D&S ISA " },
                { text: "ICCP", class: "btn-data", value: "IXD ICWR5 PALLETS D&S ISA " },
                { text: "DHLGF", class: "btn-sec", value: "IXD DHLGF D&S ISA " },
                { text: "DEUTP", class: "btn-std", value: "IXD DEUTP ISA " },
                { text: "DHLFX", class: "btn-std", value: "IXD DHLFX ISA " },
                { text: "DAFIX", class: "btn-alert", value: "IXD DAFIX ISA " },
                { text: "GLSFR", class: "btn-ok", value: "IXD GLSFR ISA " }
            ]
        },
        page2: {
            "SYSTEM_GENERAL": [
                { text: "RESET", class: "btn-reset", value: " " },
                { text: "SHIPL", class: "btn-std", value: "SHIP LOAD: " },
                { text: "RENTAL", class: "btn-std", value: "RENTAL VS4 " }
            ],
            "CEQP_STORAGE": [
                { text: "FWBF1", class: "btn-alert", value: "CEQP FWBF1 TRAILER " },
                { text: "F1PALL", class: "btn-alert", value: "CEQP FWBF1 TRAILER NEQP PALLETS " },
                { text: "FWBK1", class: "btn-data", value: "CEQP FWBK1 TRAILER " },
                { text: "FWBK2", class: "btn-data", value: "CEQP FWBK2 TRAILER " },
                { text: "FWBS1", class: "btn-ok", value: "CEQP FWBS1 TRAILER " },
                { text: "STOREIB", class: "btn-sec", value: "EMPTY STORE IB" },
                { text: "STOREOB", class: "btn-sec", value: "EMPTY STORE OB" }
            ]
        }
    };

    // --- CSS INJECTION (Natywne Zagnieżdżanie) ---
    function injectStyles() {
        GM_addStyle(`
            ::-webkit-scrollbar{display:none}*{scrollbar-width:none;-ms-overflow-style:none}:root{--accent:${THEME.ACCENT};--bg:${THEME.BG_DARK};--sec:${THEME.SECONDARY};--data:${THEME.DATA_WHITE};--success:${THEME.SUCCESS};--info:${THEME.INFO}}body.oxy-dark-mode{background:var(--bg) !important;color:var(--data) !important;.table,.ship-clerk-dashboard-table{background:#111 !important;border:1px solid var(--sec) !important;border-radius:0 !important}th{background:#1a1a1a !important;color:var(--accent) !important;border-bottom:2px solid var(--accent) !important;text-transform:uppercase;letter-spacing:0.2rem}tr{border-bottom:1px solid #222 !important;&:hover td{background:rgba(255,255,255,0.05) !important}}}body.oxy-filter-active .ship-clerk-dashboard-table tbody{tr{display:none}tr.oxy-important-row{display:table-row !important}}#custom-options-container{display:flex;background:rgba(18,18,18,0.95);border:1px solid var(--sec);border-radius:0;padding:10px 15px;gap:25px;margin-bottom:10px;position:sticky;top:0;z-index:9999;border-top:2px solid var(--accent);user-select:none;.panel h3{color:var(--accent);font-size:10px;text-transform:uppercase;letter-spacing:2px;margin:0 0 5px 0;font-family:'JetBrains Mono','Roboto Mono',monospace}}.oxy-switch{display:flex;align-items:center;gap:8px;cursor:pointer;user-select:none;input{display:none}.slider{width:32px;height:14px;background:var(--sec);position:relative;transition:background 0.3s ease;border-radius:0;&::after{content:'';position:absolute;top:1px;left:1px;width:12px;height:12px;background:var(--data);transition:transform 0.2s cubic-bezier(0.4,0.0,0.2,1);border-radius:0}}input:checked+.slider{background:var(--accent);&::after{transform:translateX(18px);background:#fff}}}#quickNotesContainer{background:var(--bg);border-left:3px solid var(--accent);border-radius:0;padding:12px;margin-top:10px;position:relative;font-family:'JetBrains Mono','Courier New',monospace;user-select:none;&::before{content:'';position:absolute;top:0;left:0;right:0;bottom:0;background:repeating-linear-gradient(45deg,transparent,transparent 10px,rgba(255,255,255,0.01) 10px,rgba(255,255,255,0.01) 20px);pointer-events:none}&::after{content:'SYSTEM_OXY_v3.1_OPT';position:absolute;bottom:2px;right:5px;font-size:9px;color:var(--sec);letter-spacing:1px}}.oxy-tabs{display:flex;gap:5px;margin-bottom:10px;border-bottom:1px solid var(--sec);padding-bottom:5px;.oxy-tab-btn{background:transparent;color:var(--sec);border:1px solid var(--sec);border-radius:0;padding:4px 12px;font-size:10px;cursor:pointer;font-weight:bold;transition:all 0.2s ease;text-transform:uppercase;&.active{background:var(--accent);color:#fff;border-color:var(--accent)}}}.buttonTable{width:100%;border-collapse:collapse;margin-bottom:12px;table-layout:fixed;th{text-align:left;color:var(--data);font-size:10px;padding:4px;border-bottom:1px solid var(--sec);background:repeating-linear-gradient(45deg,transparent,transparent 5px,rgba(255,255,255,0.02) 5px,rgba(255,255,255,0.02) 10px);letter-spacing:0.1rem}td{padding:3px}}.superuserButton{width:100%;border-radius:0 !important;border:1px solid var(--sec);padding:6px 2px;font-family:'JetBrains Mono','Courier New',monospace;font-size:10px;font-weight:bold;text-transform:uppercase;cursor:pointer;transition:background 0.15s ease,color 0.15s ease;background:transparent;color:var(--data);white-space:nowrap;overflow:hidden;text-overflow:ellipsis;&:hover{background:var(--data);color:var(--bg);border-color:var(--data)}&:active{transform:none;background:var(--accent);border-color:var(--accent);color:#fff}}.btn-alert{border-color:var(--accent);color:var(--accent)}.btn-alert:hover{background:var(--accent);color:#fff;border-color:var(--accent)}.btn-ok{border-color:var(--success);color:var(--success)}.btn-ok:hover{background:var(--success);color:var(--bg);border-color:var(--success)}.btn-data{border-color:var(--info);color:var(--info)}.btn-data:hover{background:var(--info);color:#fff;border-color:var(--info)}.btn-sec{border-color:#777;color:#aaa}.copy-trigger{display:inline-flex;justify-content:center;align-items:center;width:14px;height:14px;border:1px solid var(--accent);background:var(--accent);cursor:pointer;margin-left:6px;vertical-align:middle;transition:background 0.2s,border-color 0.2s;position:relative;border-radius:0;&::before{content:'';width:6px;height:6px;background:var(--bg);transition:transform 0.2s ease,background 0.2s ease;border-radius:0}&:hover::before{background:#fff;transform:scale(0.8)}&.copied{background:var(--success);border-color:var(--success);&::before{content:'✓';color:var(--bg);background:transparent;font-size:10px;line-height:1;font-weight:bold;transform:none}}}
        `);
    }

    // --- HTML GENERATORS ---
    function buildNotesHTML(pageData, pageId) {
        let html = `<div id="${pageId}" class="oxy-page-content" style="display: none;">`;
        for (const [category, buttons] of Object.entries(pageData)) {
            html += `<table class="buttonTable"><tr><th colspan="5">${category}</th></tr>`;
            for (let index = 0; index < buttons.length; index++) {
                const btn = buttons[index];
                if (index % 5 === 0) html += `<tr>`;
                html += `<td><button type="button" class="superuserButton ${btn.class}" data-note="${btn.value}" title="${btn.value}">${btn.text}</button></td>`;
                if (index % 5 === 4 || index === buttons.length - 1) html += `</tr>`;
            }
            html += `</table>`;
        }
        html += `</div>`;
        return html;
    }

    // --- LOGIC FUNCTIONS ---
    function setupQuickNotes() {
        if ($("#quickNotesContainer").length || !$("#noteTextArea").is(":visible")) return;

        const html = `
            <div id="quickNotesContainer">
                <div class="oxy-tabs">
                    <button type="button" class="oxy-tab-btn active" data-target="oxyPage1">PAGE 1</button>
                    <button type="button" class="oxy-tab-btn" data-target="oxyPage2">PAGE 2</button>
                </div>
                ${buildNotesHTML(QUICK_NOTES_CONFIG.page1, 'oxyPage1')}
                ${buildNotesHTML(QUICK_NOTES_CONFIG.page2, 'oxyPage2')}
            </div>
        `;

        $("#noteTextArea").after(html);
        $("#oxyPage1").show();
    }

    function processDynamicElements() {
        const unProcessedPlates = $("span[ng-if*='vehicleNumber']:not(.oxy-processed), span[ng-if*='licensePlateIdentifier']:not(.oxy-processed)");

        if (unProcessedPlates.length > 0) {
            unProcessedPlates.each(function () {
                const $el = $(this);
                $el.addClass('oxy-processed');

                const textToCopy = $el.text().trim().split("\n")[0];
                if (textToCopy) {
                    const triggerHtml = `<span class="copy-trigger" title="COPY_DATA" data-copy="${textToCopy}"></span>`;
                    $el.after(triggerHtml);
                }
            });
        }

        if ($("body").hasClass("oxy-filter-active")) {
            tagImportantRows();
        }
    }

    function tagImportantRows() {
        $(".ship-clerk-dashboard-table tbody tr:not(.oxy-important-row)").each(function () {
            const $row = $(this);
            const hasStatus = $row.find('.yard-asset-yellow, .yard-asset-red').length > 0;
            const hasMasterLP = $row.find('.masterYardLP td:nth-child(2)').text().trim() !== "";

            if (hasStatus || hasMasterLP) {
                $row.addClass('oxy-important-row');
            }
        });
    }

    function initUI() {
        if ($("#custom-options-container").length) return;

        const uiHtml = `
            <div id="custom-options-container">
                <div class="panel">
                    <h3>SYSTEM_THEME</h3>
                    <label class="oxy-switch">
                        <input id="oxy-dark-toggle" type="checkbox" checked>
                        <span class="slider"></span>
                        <span style="font-size: 10px; color: var(--data); font-family: monospace;">OXY_DARK</span>
                    </label>
                </div>
                <div class="panel">
                    <h3>DATA_FILTER</h3>
                    <label class="oxy-switch">
                        <input id="oxy-filter-toggle" type="checkbox">
                        <span class="slider"></span>
                        <span style="font-size: 10px; color: var(--data); font-family: monospace;">TAGGED_ONLY</span>
                    </label>
                </div>
            </div>
        `;

        $('#mainContainer').before(uiHtml);
        $('body').addClass('oxy-dark-mode');
    }

    // --- INITIALIZATION & EVENT DELEGATION ---
    function main() {
        injectStyles();
        initUI();

        // 1. Kopiowanie rejestracji
        $(document).on('click', '.copy-trigger', function () {
            const $btn = $(this);
            const text = $btn.data('copy');

            navigator.clipboard.writeText(text).then(() => {
                $btn.addClass('copied');
                setTimeout(() => $btn.removeClass('copied'), 1200);
            });
        });

        // 2. Klikanie Notatek (Quick Notes) - Poprawka dla frameworków SPA (Angular/React)
        $(document).on('click', '.superuserButton', function () {
            const noteVal = $(this).data('note');
            const $textarea = $("#noteTextArea");

            if ($textarea.length) {
                const el = $textarea.get(0);
                $textarea.val(noteVal);

                // Aby Angular/React zarejestrował zmianę programistyczną:
                el.dispatchEvent(new Event("input", { bubbles: true }));
                el.dispatchEvent(new Event("change", { bubbles: true }));
            }
        });

        // 3. Przełączanie zakładek z notatkami
        $(document).on('click', '.oxy-tab-btn', function () {
            $('.oxy-tab-btn').removeClass('active');
            $(this).addClass('active');

            $('.oxy-page-content').hide();
            $('#' + $(this).data('target')).show();
        });

        // 4. Panel sterowania (Toggles)
        $(document).on('change', '#oxy-dark-toggle', function () {
            $('body').toggleClass('oxy-dark-mode', this.checked);
        });

        $(document).on('change', '#oxy-filter-toggle', function () {
            const isActive = this.checked;
            $('body').toggleClass('oxy-filter-active', isActive);
            if (isActive) tagImportantRows();
        });

        // --- DEBOUNCED MUTATION OBSERVER ---
        let observerTimeout;
        const observer = new MutationObserver(() => {
            clearTimeout(observerTimeout);
            observerTimeout = setTimeout(() => {
                setupQuickNotes();
                processDynamicElements();
            }, 150);
        });

        observer.observe(document.body, { childList: true, subtree: true });
    }

    $(document).ready(main);

})(jQuery, window, document);"}
